+fn consume_word_token(bytes: &[u8], mut i: usize, len: usize) -> usize {
+    while i < len {
+        let b = bytes[i];
+
+        if b.is_ascii_whitespace() {
+            break;
+        }
+
+        if matches!(b, b'|' | b';' | b'&' | b'(' | b')') {
+            break;
+        }
+
