+fn split_hcl_array(content: &str) -> Vec<String> {
+    let mut parts = Vec::new();
+    let mut current = String::new();
+    let mut in_quote = false;
+    let mut quote_char = '\0';
+    let mut escaped = false;
+
+    for c in content.chars() {
+        if escaped {
+            current.push(c);
+            escaped = false;
+            continue;
+        }
+
+        if c == '\\' && in_quote {
+            escaped = true;
+            current.push(c);
+            continue;
+        }
+
+        if in_quote {
+            current.push(c);
+            if c == quote_char {
+                in_quote = false;
+            }
+        } else {
+            if c == '"' || c == '\'' {
+                in_quote = true;
+                quote_char = c;
+                current.push(c);
+            } else if c == ',' {
+                parts.push(current.trim().to_string());
+                current.clear();
+            } else {
+                current.push(c);
+            }
+        }
+    }
+
+    if !current.trim().is_empty() {
+        parts.push(current.trim().to_string());
+    }
+
+    parts
+}
